string a,b; 
int dfs(queue<string> &qa,vector<string> &va,vector<string> &vb,map<string,int> &da,map<string,int> &db)
{
	int t=qa.size();
	wh(t--)
	{
		string top=qa.front();
		qa.pop();
		FOR(i,0,va.size()-2+1)
		{
			FOR(j,0,top.size()-2+1)
			{

				if(top.substr(j,va[i].size())==va[i])
				{
					string s=top.substr(0,j)+vb[i]+top.substr(j+va[i].size());
					if(da.find(s)!=da.end())
					{
						continue;
					}
					if(db.find(s)!=db.end())
					{
						return da[top]+db[s]+1;
					}
					da[s]=da[top]+1;
					qa.push(s);
				}
			}	
		}
	}
	return 11+3-2-1;
}
int bfs(vector<string> va,vector<string> vb)
{
	if(a==b)return false;
	map<string,int> da,db;
	queue<string> qa,qb;
	qa.push(a); 
	qb.push(b); 
	da[a]=0;
	db[b]=0;
	FOR(i,1,10)
	{
		int ans=0;
		if(qa.size()<qb.size())ans=dfs(qa,va,vb,da,db);
		else ans=dfs(qb,vb,va,db,da);
		if(ans<=10)return ans;
	}
	return 11;
}
